  4101 |   ICmpInst::Predicate SrcPred;
  4102 |   Value *X;
  4103 |   const APInt *C0, *C1; // FIXME: non-splats, potentially with undef.
  4104 |   // We are ok with 'shl' having multiple uses, but 'ashr' must be one-use.
  4105 |   if (!match(&I, m_c_ICmp(SrcPred,
  4106 |                           m_OneUse(m_AShr(m_Shl(m_Value(X), m_APInt(C0)),
  4107 |                                           m_APInt(C1))),
  4108 |                           m_Deferred(X))))
  4109 |     return nullptr;
  4110 | 
  4111 |   // Potential handling of non-splats: for each element:
  4112 |   //  * if both are undef, replace with constant 0.
  4113 |   //    Because (1<<0) is OK and is 1, and ((1<<0)>>1) is also OK and is 0.
  4114 |   //  * if both are not undef, and are different, bailout.
  4115 |   //  * else, only one is undef, then pick the non-undef one.
  4116 | 
  4117 |   // The shift amount must be equal.
  4118 |   if (*C0 != *C1)
  4119 |     return nullptr;
  4120 |   const APInt &MaskedBits = *C0;
  4121 |   assert(MaskedBits != 0 && "shift by zero should be folded away already.");
  4122 | 
  4123 |   ICmpInst::Predicate DstPred;
  4124 |   switch (SrcPred) {
  4125 |   case ICmpInst::Predicate::ICMP_EQ:
  4126 |     // ((%x << MaskedBits) a>> MaskedBits) == %x
  4127 |     //   =>
  4128 |     // (add %x, (1 << (KeptBits-1))) u< (1 << KeptBits)
  4129 |     DstPred = ICmpInst::Predicate::ICMP_ULT;
  4130 |     break;
  4131 |   case ICmpInst::Predicate::ICMP_NE:
  4132 |     // ((%x << MaskedBits) a>> MaskedBits) != %x
  4133 |     //   =>
  4134 |     // (add %x, (1 << (KeptBits-1))) u>= (1 << KeptBits)
  4135 |     DstPred = ICmpInst::Predicate::ICMP_UGE;
  4136 |     break;
  4137 |   // FIXME: are more folds possible?
  4138 |   default:
  4139 |     return nullptr;
  4140 |   }
  4141 | 
  4142 |   auto *XType = X->getType();
  4143 |   const unsigned XBitWidth = XType->getScalarSizeInBits();
  4144 |   const APInt BitWidth = APInt(XBitWidth, XBitWidth);
  4145 |   assert(BitWidth.ugt(MaskedBits) && "shifts should leave some bits untouched");
  4146 | 
  4147 |   // KeptBits = bitwidth(%x) - MaskedBits
  4148 |   const APInt KeptBits = BitWidth - MaskedBits;
  4149 |   assert(KeptBits.ugt(0) && KeptBits.ult(BitWidth) && "unreachable");
  4150 |   // ICmpCst = (1 << KeptBits)
  4151 |   const APInt ICmpCst = APInt(XBitWidth, 1).shl(KeptBits);
  4152 |   assert(ICmpCst.isPowerOf2());
  4153 |   // AddCst = (1 << (KeptBits-1))
  4154 |   const APInt AddCst = ICmpCst.lshr(1);
  4155 |   assert(AddCst.ult(ICmpCst) && AddCst.isPowerOf2());
  4156 | 
  4157 |   // T0 = add %x, AddCst
  4158 |   Value *T0 = Builder.CreateAdd(X, ConstantInt::get(XType, AddCst));
  4159 |   // T1 = T0 DstPred ICmpCst
  4160 |   Value *T1 = Builder.CreateICmp(DstPred, T0, ConstantInt::get(XType, ICmpCst));
  4161 | 
  4162 |   return T1;
  4163 | }
