  4165 | // Given pattern:
  4166 | //   icmp eq/ne (and ((x shift Q), (y oppositeshift K))), 0
  4167 | // we should move shifts to the same hand of 'and', i.e. rewrite as
  4168 | //   icmp eq/ne (and (x shift (Q+K)), y), 0  iff (Q+K) u< bitwidth(x)
  4169 | // We are only interested in opposite logical shifts here.
  4170 | // One of the shifts can be truncated.
  4171 | // If we can, we want to end up creating 'lshr' shift.
  4172 | static Value *
  4173 | foldShiftIntoShiftInAnotherHandOfAndInICmp(ICmpInst &I, const SimplifyQuery SQ,
  4174 |                                            InstCombiner::BuilderTy &Builder) {
  4175 |   if (!I.isEquality() || !match(I.getOperand(1), m_Zero()) ||
  4176 |       !I.getOperand(0)->hasOneUse())
  4177 |     return nullptr;
  4178 | 
  4179 |   auto m_AnyLogicalShift = m_LogicalShift(m_Value(), m_Value());
  4180 | 
  4181 |   // Look for an 'and' of two logical shifts, one of which may be truncated.
  4182 |   // We use m_TruncOrSelf() on the RHS to correctly handle commutative case.
  4183 |   Instruction *XShift, *MaybeTruncation, *YShift;
  4184 |   if (!match(
  4185 |           I.getOperand(0),
  4186 |           m_c_And(m_CombineAnd(m_AnyLogicalShift, m_Instruction(XShift)),
  4187 |                   m_CombineAnd(m_TruncOrSelf(m_CombineAnd(
  4188 |                                    m_AnyLogicalShift, m_Instruction(YShift))),
  4189 |                                m_Instruction(MaybeTruncation)))))
  4190 |     return nullptr;
  4191 | 
  4192 |   // We potentially looked past 'trunc', but only when matching YShift,
  4193 |   // therefore YShift must have the widest type.
  4194 |   Instruction *WidestShift = YShift;
  4195 |   // Therefore XShift must have the shallowest type.
  4196 |   // Or they both have identical types if there was no truncation.
  4197 |   Instruction *NarrowestShift = XShift;
  4198 | 
  4199 |   Type *WidestTy = WidestShift->getType();
  4200 |   Type *NarrowestTy = NarrowestShift->getType();
  4201 |   assert(NarrowestTy == I.getOperand(0)->getType() &&
  4202 |          "We did not look past any shifts while matching XShift though.");
  4203 |   bool HadTrunc = WidestTy != I.getOperand(0)->getType();
  4204 | 
  4205 |   // If YShift is a 'lshr', swap the shifts around.
  4206 |   if (match(YShift, m_LShr(m_Value(), m_Value())))
  4207 |     std::swap(XShift, YShift);
  4208 | 
  4209 |   // The shifts must be in opposite directions.
  4210 |   auto XShiftOpcode = XShift->getOpcode();
  4211 |   if (XShiftOpcode == YShift->getOpcode())
  4212 |     return nullptr; // Do not care about same-direction shifts here.
  4213 | 
  4214 |   Value *X, *XShAmt, *Y, *YShAmt;
  4215 |   match(XShift, m_BinOp(m_Value(X), m_ZExtOrSelf(m_Value(XShAmt))));
  4216 |   match(YShift, m_BinOp(m_Value(Y), m_ZExtOrSelf(m_Value(YShAmt))));
  4217 | 
  4218 |   // If one of the values being shifted is a constant, then we will end with
  4219 |   // and+icmp, and [zext+]shift instrs will be constant-folded. If they are not,
  4220 |   // however, we will need to ensure that we won't increase instruction count.
  4221 |   if (!isa<Constant>(X) && !isa<Constant>(Y)) {
  4222 |     // At least one of the hands of the 'and' should be one-use shift.
  4223 |     if (!match(I.getOperand(0),
  4224 |                m_c_And(m_OneUse(m_AnyLogicalShift), m_Value())))
  4225 |       return nullptr;
  4226 |     if (HadTrunc) {
  4227 |       // Due to the 'trunc', we will need to widen X. For that either the old
  4228 |       // 'trunc' or the shift amt in the non-truncated shift should be one-use.
  4229 |       if (!MaybeTruncation->hasOneUse() &&
  4230 |           !NarrowestShift->getOperand(1)->hasOneUse())
  4231 |         return nullptr;
  4232 |     }
  4233 |   }
  4234 | 
  4235 |   // We have two shift amounts from two different shifts. The types of those
  4236 |   // shift amounts may not match. If that's the case let's bailout now.
  4237 |   if (XShAmt->getType() != YShAmt->getType())
  4238 |     return nullptr;
  4239 | 
  4240 |   // As input, we have the following pattern:
  4241 |   //   icmp eq/ne (and ((x shift Q), (y oppositeshift K))), 0
  4242 |   // We want to rewrite that as:
  4243 |   //   icmp eq/ne (and (x shift (Q+K)), y), 0  iff (Q+K) u< bitwidth(x)
  4244 |   // While we know that originally (Q+K) would not overflow
  4245 |   // (because  2 * (N-1) u<= iN -1), we have looked past extensions of
  4246 |   // shift amounts. so it may now overflow in smaller bitwidth.
  4247 |   // To ensure that does not happen, we need to ensure that the total maximal
  4248 |   // shift amount is still representable in that smaller bit width.
  4249 |   unsigned MaximalPossibleTotalShiftAmount =
  4250 |       (WidestTy->getScalarSizeInBits() - 1) +
  4251 |       (NarrowestTy->getScalarSizeInBits() - 1);
  4252 |   APInt MaximalRepresentableShiftAmount =
  4253 |       APInt::getAllOnes(XShAmt->getType()->getScalarSizeInBits());
  4254 |   if (MaximalRepresentableShiftAmount.ult(MaximalPossibleTotalShiftAmount))
  4255 |     return nullptr;
  4256 | 
  4257 |   // Can we fold (XShAmt+YShAmt) ?
  4258 |   auto *NewShAmt = dyn_cast_or_null<Constant>(
  4259 |       simplifyAddInst(XShAmt, YShAmt, /*isNSW=*/false,
  4260 |                       /*isNUW=*/false, SQ.getWithInstruction(&I)));
  4261 |   if (!NewShAmt)
  4262 |     return nullptr;
  4263 |   if (NewShAmt->getType() != WidestTy) {
  4264 |     NewShAmt =
  4265 |         ConstantFoldCastOperand(Instruction::ZExt, NewShAmt, WidestTy, SQ.DL);
  4266 |     if (!NewShAmt)
  4267 |       return nullptr;
  4268 |   }
  4269 |   unsigned WidestBitWidth = WidestTy->getScalarSizeInBits();
  4270 | 
  4271 |   // Is the new shift amount smaller than the bit width?
  4272 |   // FIXME: could also rely on ConstantRange.
  4273 |   if (!match(NewShAmt,
  4274 |              m_SpecificInt_ICMP(ICmpInst::Predicate::ICMP_ULT,
  4275 |                                 APInt(WidestBitWidth, WidestBitWidth))))
  4276 |     return nullptr;
  4277 | 
  4278 |   // An extra legality check is needed if we had trunc-of-lshr.
  4279 |   if (HadTrunc && match(WidestShift, m_LShr(m_Value(), m_Value()))) {
  4280 |     auto CanFold = [NewShAmt, WidestBitWidth, NarrowestShift, SQ,
  4281 |                     WidestShift]() {
  4282 |       // It isn't obvious whether it's worth it to analyze non-constants here.
  4283 |       // Also, let's basically give up on non-splat cases, pessimizing vectors.
  4284 |       // If *any* of these preconditions matches we can perform the fold.
  4285 |       Constant *NewShAmtSplat = NewShAmt->getType()->isVectorTy()
  4286 |                                     ? NewShAmt->getSplatValue()
  4287 |                                     : NewShAmt;
  4288 |       // If it's edge-case shift (by 0 or by WidestBitWidth-1) we can fold.
  4289 |       if (NewShAmtSplat &&
  4290 |           (NewShAmtSplat->isNullValue() ||
  4291 |            NewShAmtSplat->getUniqueInteger() == WidestBitWidth - 1))
  4292 |         return true;
  4293 |       // We consider *min* leading zeros so a single outlier
  4294 |       // blocks the transform as opposed to allowing it.
  4295 |       if (auto *C = dyn_cast<Constant>(NarrowestShift->getOperand(0))) {
  4296 |         KnownBits Known = computeKnownBits(C, SQ.DL);
  4297 |         unsigned MinLeadZero = Known.countMinLeadingZeros();
  4298 |         // If the value being shifted has at most lowest bit set we can fold.
  4299 |         unsigned MaxActiveBits = Known.getBitWidth() - MinLeadZero;
  4300 |         if (MaxActiveBits <= 1)
  4301 |           return true;
  4302 |         // Precondition:  NewShAmt u<= countLeadingZeros(C)
  4303 |         if (NewShAmtSplat && NewShAmtSplat->getUniqueInteger().ule(MinLeadZero))
  4304 |           return true;
  4305 |       }
  4306 |       if (auto *C = dyn_cast<Constant>(WidestShift->getOperand(0))) {
  4307 |         KnownBits Known = computeKnownBits(C, SQ.DL);
  4308 |         unsigned MinLeadZero = Known.countMinLeadingZeros();
  4309 |         // If the value being shifted has at most lowest bit set we can fold.
  4310 |         unsigned MaxActiveBits = Known.getBitWidth() - MinLeadZero;
  4311 |         if (MaxActiveBits <= 1)
  4312 |           return true;
  4313 |         // Precondition:  ((WidestBitWidth-1)-NewShAmt) u<= countLeadingZeros(C)
  4314 |         if (NewShAmtSplat) {
  4315 |           APInt AdjNewShAmt =
  4316 |               (WidestBitWidth - 1) - NewShAmtSplat->getUniqueInteger();
  4317 |           if (AdjNewShAmt.ule(MinLeadZero))
  4318 |             return true;
  4319 |         }
  4320 |       }
  4321 |       return false; // Can't tell if it's ok.
  4322 |     };
  4323 |     if (!CanFold())
  4324 |       return nullptr;
  4325 |   }
  4326 | 
  4327 |   // All good, we can do this fold.
  4328 |   X = Builder.CreateZExt(X, WidestTy);
  4329 |   Y = Builder.CreateZExt(Y, WidestTy);
  4330 |   // The shift is the same that was for X.
  4331 |   Value *T0 = XShiftOpcode == Instruction::BinaryOps::LShr
  4332 |                   ? Builder.CreateLShr(X, NewShAmt)
  4333 |                   : Builder.CreateShl(X, NewShAmt);
  4334 |   Value *T1 = Builder.CreateAnd(T0, Y);
  4335 |   return Builder.CreateICmp(I.getPredicate(), T1,
  4336 |                             Constant::getNullValue(WidestTy));
  4337 | }
