  4339 | /// Fold
  4340 | ///   (-1 u/ x) u< y
  4341 | ///   ((x * y) ?/ x) != y
  4342 | /// to
  4343 | ///   @llvm.?mul.with.overflow(x, y) plus extraction of overflow bit
  4344 | /// Note that the comparison is commutative, while inverted (u>=, ==) predicate
  4345 | /// will mean that we are looking for the opposite answer.
  4346 | Value *InstCombinerImpl::foldMultiplicationOverflowCheck(ICmpInst &I) {
  4347 |   ICmpInst::Predicate Pred;
  4348 |   Value *X, *Y;
  4349 |   Instruction *Mul;
  4350 |   Instruction *Div;
  4351 |   bool NeedNegation;
  4352 |   // Look for: (-1 u/ x) u</u>= y
  4353 |   if (!I.isEquality() &&
  4354 |       match(&I, m_c_ICmp(Pred,
  4355 |                          m_CombineAnd(m_OneUse(m_UDiv(m_AllOnes(), m_Value(X))),
  4356 |                                       m_Instruction(Div)),
  4357 |                          m_Value(Y)))) {
  4358 |     Mul = nullptr;
  4359 | 
  4360 |     // Are we checking that overflow does not happen, or does happen?
  4361 |     switch (Pred) {
  4362 |     case ICmpInst::Predicate::ICMP_ULT:
  4363 |       NeedNegation = false;
  4364 |       break; // OK
  4365 |     case ICmpInst::Predicate::ICMP_UGE:
  4366 |       NeedNegation = true;
  4367 |       break; // OK
  4368 |     default:
  4369 |       return nullptr; // Wrong predicate.
  4370 |     }
  4371 |   } else // Look for: ((x * y) / x) !=/== y
  4372 |       if (I.isEquality() &&
  4373 |           match(&I,
  4374 |                 m_c_ICmp(Pred, m_Value(Y),
  4375 |                          m_CombineAnd(
  4376 |                              m_OneUse(m_IDiv(m_CombineAnd(m_c_Mul(m_Deferred(Y),
  4377 |                                                                   m_Value(X)),
  4378 |                                                           m_Instruction(Mul)),
  4379 |                                              m_Deferred(X))),
  4380 |                              m_Instruction(Div))))) {
  4381 |     NeedNegation = Pred == ICmpInst::Predicate::ICMP_EQ;
  4382 |   } else
  4383 |     return nullptr;
  4384 | 
  4385 |   BuilderTy::InsertPointGuard Guard(Builder);
  4386 |   // If the pattern included (x * y), we'll want to insert new instructions
  4387 |   // right before that original multiplication so that we can replace it.
  4388 |   bool MulHadOtherUses = Mul && !Mul->hasOneUse();
  4389 |   if (MulHadOtherUses)
  4390 |     Builder.SetInsertPoint(Mul);
  4391 | 
  4392 |   Function *F = Intrinsic::getDeclaration(I.getModule(),
  4393 |                                           Div->getOpcode() == Instruction::UDiv
  4394 |                                               ? Intrinsic::umul_with_overflow
  4395 |                                               : Intrinsic::smul_with_overflow,
  4396 |                                           X->getType());
  4397 |   CallInst *Call = Builder.CreateCall(F, {X, Y}, "mul");
  4398 | 
  4399 |   // If the multiplication was used elsewhere, to ensure that we don't leave
  4400 |   // "duplicate" instructions, replace uses of that original multiplication
  4401 |   // with the multiplication result from the with.overflow intrinsic.
  4402 |   if (MulHadOtherUses)
  4403 |     replaceInstUsesWith(*Mul, Builder.CreateExtractValue(Call, 0, "mul.val"));
  4404 | 
  4405 |   Value *Res = Builder.CreateExtractValue(Call, 1, "mul.ov");
  4406 |   if (NeedNegation) // This technically increases instruction count.
  4407 |     Res = Builder.CreateNot(Res, "mul.not.ov");
  4408 | 
  4409 |   // If we replaced the mul, erase it. Do this after all uses of Builder,
  4410 |   // as the mul is used as insertion point.
  4411 |   if (MulHadOtherUses)
  4412 |     eraseInstFromFunction(*Mul);
  4413 | 
  4414 |   return Res;
  4415 | }
