  4417 | static Instruction *foldICmpXNegX(ICmpInst &I,
  4418 |                                   InstCombiner::BuilderTy &Builder) {
  4419 |   CmpInst::Predicate Pred;
  4420 |   Value *X;
  4421 |   if (match(&I, m_c_ICmp(Pred, m_NSWNeg(m_Value(X)), m_Deferred(X)))) {
  4422 | 
  4423 |     if (ICmpInst::isSigned(Pred))
  4424 |       Pred = ICmpInst::getSwappedPredicate(Pred);
  4425 |     else if (ICmpInst::isUnsigned(Pred))
  4426 |       Pred = ICmpInst::getSignedPredicate(Pred);
  4427 |     // else for equality-comparisons just keep the predicate.
  4428 | 
  4429 |     return ICmpInst::Create(Instruction::ICmp, Pred, X,
  4430 |                             Constant::getNullValue(X->getType()), I.getName());
  4431 |   }
  4432 | 
  4433 |   // A value is not equal to its negation unless that value is 0 or
  4434 |   // MinSignedValue, ie: a != -a --> (a & MaxSignedVal) != 0
  4435 |   if (match(&I, m_c_ICmp(Pred, m_OneUse(m_Neg(m_Value(X))), m_Deferred(X))) &&
  4436 |       ICmpInst::isEquality(Pred)) {
  4437 |     Type *Ty = X->getType();
  4438 |     uint32_t BitWidth = Ty->getScalarSizeInBits();
  4439 |     Constant *MaxSignedVal =
  4440 |         ConstantInt::get(Ty, APInt::getSignedMaxValue(BitWidth));
  4441 |     Value *And = Builder.CreateAnd(X, MaxSignedVal);
  4442 |     Constant *Zero = Constant::getNullValue(Ty);
  4443 |     return CmpInst::Create(Instruction::ICmp, Pred, And, Zero);
  4444 |   }
  4445 | 
  4446 |   return nullptr;
  4447 | }
