  4449 | static Instruction *foldICmpAndXX(ICmpInst &I, const SimplifyQuery &Q,
  4450 |                                   InstCombinerImpl &IC) {
  4451 |   Value *Op0 = I.getOperand(0), *Op1 = I.getOperand(1), *A;
  4452 |   // Normalize and operand as operand 0.
  4453 |   CmpInst::Predicate Pred = I.getPredicate();
  4454 |   if (match(Op1, m_c_And(m_Specific(Op0), m_Value()))) {
  4455 |     std::swap(Op0, Op1);
  4456 |     Pred = ICmpInst::getSwappedPredicate(Pred);
  4457 |   }
  4458 | 
  4459 |   if (!match(Op0, m_c_And(m_Specific(Op1), m_Value(A))))
  4460 |     return nullptr;
  4461 | 
  4462 |   // (icmp (X & Y) u< X --> (X & Y) != X
  4463 |   if (Pred == ICmpInst::ICMP_ULT)
  4464 |     return new ICmpInst(ICmpInst::ICMP_NE, Op0, Op1);
  4465 | 
  4466 |   // (icmp (X & Y) u>= X --> (X & Y) == X
  4467 |   if (Pred == ICmpInst::ICMP_UGE)
  4468 |     return new ICmpInst(ICmpInst::ICMP_EQ, Op0, Op1);
  4469 | 
  4470 |   return nullptr;
  4471 | }
