  4473 | static Instruction *foldICmpOrXX(ICmpInst &I, const SimplifyQuery &Q,
  4474 |                                  InstCombinerImpl &IC) {
  4475 |   Value *Op0 = I.getOperand(0), *Op1 = I.getOperand(1), *A;
  4476 | 
  4477 |   // Normalize or operand as operand 0.
  4478 |   CmpInst::Predicate Pred = I.getPredicate();
  4479 |   if (match(Op1, m_c_Or(m_Specific(Op0), m_Value(A)))) {
  4480 |     std::swap(Op0, Op1);
  4481 |     Pred = ICmpInst::getSwappedPredicate(Pred);
  4482 |   } else if (!match(Op0, m_c_Or(m_Specific(Op1), m_Value(A)))) {
  4483 |     return nullptr;
  4484 |   }
  4485 | 
  4486 |   // icmp (X | Y) u<= X --> (X | Y) == X
  4487 |   if (Pred == ICmpInst::ICMP_ULE)
  4488 |     return new ICmpInst(ICmpInst::ICMP_EQ, Op0, Op1);
  4489 | 
  4490 |   // icmp (X | Y) u> X --> (X | Y) != X
  4491 |   if (Pred == ICmpInst::ICMP_UGT)
  4492 |     return new ICmpInst(ICmpInst::ICMP_NE, Op0, Op1);
  4493 | 
  4494 |   if (ICmpInst::isEquality(Pred) && Op0->hasOneUse()) {
  4495 |     // icmp (X | Y) eq/ne Y --> (X & ~Y) eq/ne 0 if Y is freely invertible
  4496 |     if (IC.isFreeToInvert(Op1, Op1->hasOneUse()))
  4497 |       return new ICmpInst(Pred,
  4498 |                           IC.Builder.CreateAnd(A, IC.Builder.CreateNot(Op1)),
  4499 |                           Constant::getNullValue(Op1->getType()));
  4500 |     // icmp (X | Y) eq/ne Y --> (~X | Y) eq/ne -1 if X  is freely invertible.
  4501 |     if (IC.isFreeToInvert(A, A->hasOneUse()))
  4502 |       return new ICmpInst(Pred,
  4503 |                           IC.Builder.CreateOr(Op1, IC.Builder.CreateNot(A)),
  4504 |                           Constant::getAllOnesValue(Op1->getType()));
  4505 |   }
  4506 |   return nullptr;
  4507 | }
