  4509 | static Instruction *foldICmpXorXX(ICmpInst &I, const SimplifyQuery &Q,
  4510 |                                   InstCombinerImpl &IC) {
  4511 |   Value *Op0 = I.getOperand(0), *Op1 = I.getOperand(1), *A;
  4512 |   // Normalize xor operand as operand 0.
  4513 |   CmpInst::Predicate Pred = I.getPredicate();
  4514 |   if (match(Op1, m_c_Xor(m_Specific(Op0), m_Value()))) {
  4515 |     std::swap(Op0, Op1);
  4516 |     Pred = ICmpInst::getSwappedPredicate(Pred);
  4517 |   }
  4518 |   if (!match(Op0, m_c_Xor(m_Specific(Op1), m_Value(A))))
  4519 |     return nullptr;
  4520 | 
  4521 |   // icmp (X ^ Y_NonZero) u>= X --> icmp (X ^ Y_NonZero) u> X
  4522 |   // icmp (X ^ Y_NonZero) u<= X --> icmp (X ^ Y_NonZero) u< X
  4523 |   // icmp (X ^ Y_NonZero) s>= X --> icmp (X ^ Y_NonZero) s> X
  4524 |   // icmp (X ^ Y_NonZero) s<= X --> icmp (X ^ Y_NonZero) s< X
  4525 |   CmpInst::Predicate PredOut = CmpInst::getStrictPredicate(Pred);
  4526 |   if (PredOut != Pred &&
  4527 |       isKnownNonZero(A, Q.DL, /*Depth=*/0, Q.AC, Q.CxtI, Q.DT))
  4528 |     return new ICmpInst(PredOut, Op0, Op1);
  4529 | 
  4530 |   return nullptr;
